select COMPKEY , COOUTIT as EOASNIT , case when DOCTYPE = '310' then 'WHOLESALE' when DOCTYPE != '310' then MNGWHKY end as WAREKEY , '400' as DOCCATE , case when DOCTYPE = '310' then '440' when DOCTYPE = '330' then '445' when DOCTYPE = '350' then '450' when DOCTYPE = '360' then '460' end as DOCTYPE , 'NEW' as ASNSTAT , OWNERKY , SKUMKEY , (SELECT SKUDESC FROM mskuwc WHERE COMPKEY = OC.COMPKEY AND OWNERKY = OC.OWNERKY AND WAREKEY = OC.MNGWHKY AND SKUMKEY = OC.SKUMKEY) as SKUDESC , SKUSKEY , ' ' as SIRBCOD , to_char(now(),'YYYYMMDD') as ASNDATE , 0 as POITQTY , 'EA' as PUOMKEY , SOITQTY as ASNDQTY , 'EA' as AUOMKEY , 0 as RCHSQTY , 'EA' as RCHSUOM , case when DOCTYPE = '310' then MNGWHKY when (DOCTYPE = '330' or DOCTYPE = '340') then VENDKEY when DOCTYPE != '310' then CUSTKEY end as VENDKEY , ' ' as CARRKEY , ' ' as TRUCKNO , ' ' as TRUCTON , ' ' as PRODDAT , 0 as SHELIFE , ' ' as EXPIDAT , CUSTKEY as CUSTKEY , case when DOCTYPE = '330' AND ( SELECT COUNT(1) FROM mptnma where 1=1 and COMPKEY = OC.COMPKEY and OWNERKY = OC.OWNERKY and PTDELYN = 'N' and PTNGRO1 = 'LABEL' and PTNRTYP = 'VENDER' AND PTNRKEY = OC.CUSTKEY and PTNGRO1 not in('WAREHOUSE')) > 0 then RETAKEY
when DOCTYPE = '330' AND ( SELECT COUNT(1) FROM mptnma where 1=1 and COMPKEY = OC.COMPKEY and OWNERKY = OC.OWNERKY and PTDELYN = 'N' and PTNGRO1 = 'LABEL' and PTNRTYP = 'VENDER' AND PTNRKEY = OC.CUSTKEY and PTNGRO1 not in('WAREHOUSE')
) <= 0
then NULL ELSE CUSTKEY end as RETAKEY , 'DC' as DCTCTYP , ' ' as LOTAT01 , ' ' as LOTAT02 , ' ' as LOTAT03 , ' ' as LOTAT04 , ' ' as LOTAT05 , ' ' as LOTAT06 , ' ' as LOTAT07 , ' ' as LOTAT08 , ' ' as LOTAT09 , ' ' as LOTAT10 , ' ' as LOTAT11 , ' ' as LOTAT12 , ' ' as LOTAT13 , ' ' as LOTAT14 , ' ' as LOTAT15 , ' ' as LOTAT16 , case when DOCTYPE = '330' AND ( SELECT COUNT(1) FROM mptnma where 1=1 and COMPKEY = OC.COMPKEY and OWNERKY = OC.OWNERKY and PTDELYN = 'N' and PTNGRO1 = 'LABEL' and PTNRTYP = 'VENDER' AND PTNRKEY = OC.CUSTKEY and PTNGRO1 not in('WAREHOUSE')) > 0 then 'Y' ELSE 'N' end as LOTAT17 , case when DOCTYPE = '330' AND ( SELECT COUNT(1) FROM mptnma where 1=1 and COMPKEY = OC.COMPKEY and OWNERKY = OC.OWNERKY and PTDELYN = 'N' and PTNGRO1 = 'LABEL' and PTNRTYP = 'VENDER' AND PTNRKEY = OC.CUSTKEY and PTNGRO1 not in('WAREHOUSE')) > 0 then RETAKEY ELSE ' ' end as LOTAT18 , ' ' as LOTAT19 , ' ' as LOTAT20 , case when DOCTYPE = '310' then '80' when DOCTYPE = '350' then '90' when DOCTYPE in ('360','330') then '00' end as STKSTAT , ' ' as RSNCODE , ' ' as RCVSRMK , ' ' as COPODKY , ' ' as COPODIT , COOUTKY as REFSODC , COOUTIT as REFSOIT , ' ' as REFDNDC , ' ' as REFDNIT , ' ' as REFSDDC , ' ' as REFSDIT , CREDATE , CRETIME , CREUSER , LMODATE , LMOTIME , LMOUSER from OCOSAL OC where COMPKEY = #{compkey} AND COOUTKY = #{cooutky}

