insert into OCOSAL
(
	  COMPKEY
	, COOUTKY
	, COOUTIT
	, DOCCATE, DOCTYPE
	, SALMODE, SALGRKY, SALSTAT
	, POSTDAT
	, SALDATE, SALTIME
	, CUSTKEY, RETAKEY, VENDKEY, TOWARKY
	, SALMEMO
	, SALRQDT, SALRQTM
	, SALLBYN
	, OWNERKY
	, SKUMKEY
	, SKUDESC
	, SKUSKEY
	, SOITQTY, RGITQTY, SHCFQTY, SUOMKEY
	, PAYTYPE
	, DCTCTYP
	, MNGWHKY
	, RSNCODE, RSNDESC
	, INBSTAT, OUBSTAT
	, ITMCOST
	, SELPRIC
	, SEDPRIC
	, SEPRICE
	, ORDGR01, ORDGR02, ORDGR03
	, CLOSLYN, CLODATE, CLOTIME, CLOUSER
	, SPRETYP, PMTSAYN, PMTSADT, PMTSATM, PMTSAUR
	, CREDATE, CRETIME, CREUSER
	, LMODATE, LMOTIME, LMOUSER
)
values

(
	  #{item.compkey}
	, #{item.cooutky}, #{item.cooutit}
	, #{item.doccate}, #{item.doctype}
