	, (SELECT SKUDESC FROM mskuwc WHERE COMPKEY = #{item.compkey} AND OWNERKY = #{item.ownerky} AND WAREKEY = #{item.mngwhky} AND SKUMKEY = #{item.skumkey})
	, #{item.skuskey}
	, #{item.soitqty}, #{item.rgitqty}, #{item.shcfqty}, #{item.suomkey}
	, #{item.paytype}
	, #{item.dctctyp}
	, #{item.mngwhky}
	, #{item.rsncode}, #{item.rsndesc}
	, #{item.inbstat}, #{item.oubstat}
