	, (SELECT SELPRIC FROM mskuwc WHERE COMPKEY = #{item.compkey} AND OWNERKY = #{item.ownerky} AND WAREKEY = #{item.mngwhky} AND SKUMKEY = #{item.skumkey})
	, (SELECT SEDPRIC FROM mskuwc WHERE COMPKEY = #{item.compkey} AND OWNERKY = #{item.ownerky} AND WAREKEY = #{item.mngwhky} AND SKUMKEY = #{item.skumkey})
	, (SELECT SEPRICE FROM mskuwc WHERE COMPKEY = #{item.compkey} AND OWNERKY = #{item.ownerky} AND WAREKEY = #{item.mngwhky} AND SKUMKEY = #{item.skumkey})
	, #{item.ordgr01}, #{item.ordgr02}, #{item.ordgr03}
	, #{item.closlyn}, #{item.clodate}, #{item.clotime}, #{item.clouser}
	, #{item.spretyp}, #{item.pmtsayn}, #{item.pmtsadt}, #{item.pmtsatm}, #{item.pmtsaur}
	, to_char(now(),'YYYYMMDD'), to_char(now(),'hh24miss'), #{userData.useract}
	, to_char(now(),'YYYYMMDD'), to_char(now(),'hh24miss'), #{userData.useract}
