SELECT CONCAT(MSKU.COMPKEY, MSKU.OWNERKY, MSKU.BRANDCD, MSKU.SKUMKEY) as ROWKEY , MSKU.COMPKEY as COMPKEY , MSKU.OWNERKY as OWNERKY , MSKU.SKUMKEY as SKUMKEY , MSKU.SKUSKEY as SKUSKEY , MSKU.SKUDESC as SKUDESC , MSKU.BRANDCD as BRANDCD , IFNULL(CSTK.STOTQTY, 0) as STOTQTY , ifnull(ORDCUS.ORDDQTY, 0) as ORDHQTY , IFNULL(CSTK.STKSAMP, 0) as STKSAMP , ifnull(CSTK.STOTQTY, 0) - ifnull(ORDCUS.ORDDQTY, 0) - ifnull(CSTK.STKSAMP, 0) as STPOQTY , IFNULL(WSTK.WAREKEY, #{warekey}) as WAREKEY , IFNULL(WSTK.STKGOOD, 0) as STKGOOD , IFNULL(WSTK.STKBADS, 0) as STKBADS , ifnull(ORDWHA.ORDDQTY, 0) as ORDWQTY , ifnull(WSTK.STKGOOD, 0) - ifnull(ORDWHA.ORDDQTY, 0) as ORDMQTY FROM MSKUWC MSKU LEFT JOIN ( SELECT OWNERKY , SKUMKEY , STKSTAT , LOCAKEY , SUM(STOTQTY) AS STOTQTY , SUM(case when STKSTAT = '80' then STOTQTY else 0 end ) AS STKCUST , SUM(case when STKSTAT = '60' then STOTQTY else 0 end ) AS STKSAMP FROM WSTKKY WHERE 1=1 AND COMPKEY = #{userData.compkey} AND WAREKEY = 'WHOLESALE' AND AREAKEY = 'STG' AND LOCAKEY = #{custkey} AND STKSTAT in ('60', '80', '44') AND STOTQTY > 0 AND SALLQTY = 0 AND SINBQTY = 0 AND SOUBQTY = 0 AND SBLOQTY = 0 GROUP BY OWNERKY, SKUMKEY, STKSTAT, LOCAKEY ) CSTK ON MSKU.OWNERKY = CSTK.OWNERKY AND MSKU.SKUMKEY = CSTK.SKUMKEY AND MSKU.WAREKEY = #{warekey} LEFT JOIN ( SELECT SK.OWNERKY , SK.WAREKEY , SK.SKUMKEY , SUM(case when SK.STKSTAT = '00' then SK.STOTQTY else 0 end ) AS STKGOOD , SUM(case when SK.STKSTAT = '90' then SK.STOTQTY else 0 end ) AS STKBADS FROM WSTKKY SK INNER JOIN MSKUWC WC ON SK.OWNERKY = WC.OWNERKY AND SK.WAREKEY = WC.WAREKEY AND SK.SKUMKEY = WC.SKUMKEY WHERE 1=1 AND SK.COMPKEY = #{userData.compkey} AND SK.WAREKEY = #{warekey} AND SK.AREAKEY = 'STG' AND WC.BRANDCD = #{custkey} AND SK.STKSTAT IN ('00', '90') AND SK.STOTQTY > 0 AND SK.SALLQTY = 0 AND SK.SINBQTY = 0 AND SK.SOUBQTY = 0 AND SK.SBLOQTY = 0 GROUP BY SK.OWNERKY, SK.WAREKEY, SK.SKUMKEY ) WSTK ON MSKU.OWNERKY = WSTK.OWNERKY AND MSKU.SKUMKEY = WSTK.SKUMKEY LEFT JOIN ( SELECT OWNERKY , SKUMKEY , SUM(SOITQTY) AS ORDDQTY FROM OCOSAL WHERE COMPKEY = #{userData.compkey} AND DOCCATE = '300' AND DOCTYPE IN ('340','360','350','390') AND SALSTAT = 'ORDER' AND CUSTKEY = #{custkey} GROUP BY OWNERKY, SKUMKEY ) ORDCUS ON MSKU.OWNERKY = ORDCUS.OWNERKY AND MSKU.SKUMKEY = ORDCUS.SKUMKEY AND MSKU.WAREKEY = #{warekey} LEFT JOIN ( SELECT OWNERKY , SKUMKEY , SUM(SOITQTY) AS ORDDQTY FROM OCOSAL WHERE COMPKEY = #{userData.compkey} AND DOCCATE = '300' AND DOCTYPE IN ('310','330','379') AND SALSTAT = 'ORDER' AND CUSTKEY = #{custkey} AND MNGWHKY = #{warekey} GROUP BY OWNERKY, SKUMKEY ) ORDWHA ON MSKU.OWNERKY = ORDWHA.OWNERKY AND MSKU.SKUMKEY = ORDWHA.SKUMKEY AND MSKU.WAREKEY = #{warekey} WHERE ( WSTK.SKUMKEY > '' OR CSTK.SKUMKEY > '' or ORDCUS.SKUMKEY > '' or ORDWHA.SKUMKEY > '') AND MSKU.WAREKEY = #{warekey}
AND UPPER(MSKU.SKUDESC) like concat('%', upper(#{skudesc}), '%')
ORDER BY MSKU.SKUMKEY

SELECT CONCAT(SAL.COMPKEY, SAL.DOCTYPE, SAL.COOUTKY, SAL.COOUTIT) as ROWKEY , SAL.COMPKEY , SAL.DOCCATE , SAL.DOCTYPE , (SELECT M.DOCTYNM FROM MDOCMA M WHERE M.DOCCATE = SAL.DOCCATE AND M.DOCTYPE = SAL.DOCTYPE AND M.COMPKEY = '000') as DOCNAME , SAL.OWNERKY , SAL.MNGWHKY , SAL.SALGRKY , SAL.COOUTKY , SAL.COOUTIT , SAL.DCTCTYP , SAL.SKUMKEY , SAL.SKUDESC , SAL.SOITQTY , (SAL.SOITQTY - SAL.RGITQTY) AS SCITQTY , SAL.RGITQTY , SAL.SHCFQTY , SAL.CUSTKEY , SAL.TOWARKY , SAL.VENDKEY , ( SELECT CUS.CUNAMLC FROM MCUSMA CUS WHERE CUS.CUSTKEY = SAL.VENDKEY AND CUS.COMPKEY = SAL.COMPKEY ) AS VENDNAM , SAL.RETAKEY , ( SELECT CUS.CUNAMLC FROM MCUSMA CUS WHERE CUS.CUSTKEY = SAL.RETAKEY AND CUS.COMPKEY = #{userData.compkey} ) AS RETANAM , date_format(SAL.CREDATE, '%Y-%m-%d') as CREDATE , date_format(SAL.CRETIME, '%H-%i-%s') as CRETIME , fn_sy_usernam(SAL.COMPKEY, SAL.CREUSER) as CREUSER , SAL.UPDTCHK FROM OCOSAL SAL WHERE SAL.COMPKEY = #{userData.compkey} and SAL.DOCCATE = #{doccate} and SAL.DOCTYPE = #{doctype}
AND SAL.CREDATE >= replace(#{credafr}, '-', '')
AND SAL.CREDATE <= replace(#{credato}, '-', '')
AND SAL.SALRQDT >= replace(#{salrqfr}, '-', '')
AND SAL.SALRQDT <= replace(#{salrqto}, '-', '')
AND SAL.SALSTAT = 'ORDER'
AND SAL.SALSTAT not in ('ORDER', 'DELETE')
and SAL.SALGRKY = #{salgrky}
and SAL.CUSTKEY = #{custkey}
and SAL.TOWARKY = #{towarky}
and SAL.VENDKEY = #{vendkey}
and SAL.RETAKEY = #{retakey}

mapper.update:
    	UPDATE OCOSAL SET	
    		  SALSTAT = (case when (SOITQTY - (RGITQTY + #{item.scitqty} + DIFFQTY)) = 0 then 'ORDFM' else 'ORDER' end)
    		, RGITQTY = RGITQTY + #{item.scitqty}
    		, SHCFQTY = (case when (DOCTYPE = '310' or DOCTYPE = '330' or DOCTYPE = '370' ) then SHCFQTY 
    						  else (SHCFQTY + #{item.scitqty}) end)
    		, SALGRKY = #{item.salgrky}
    		, LMODATE = date_format(sysdate(), '%Y%m%d')
    		, LMOTIME = date_format(sysdate(), '%H%i%S')
    		, LMOUSER = #{userData.useract}								
		 where COMPKEY = #{item.compkey}																																		
		   and COOUTKY = #{item.cooutky}
		   and COOUTIT = #{item.cooutit}
		   and UPDTCHK = #{item.updtchk}

    	UPDATE OCOSAL SET	
    		  SALSTAT = 'DELETE'
    		, LMODATE = date_format(sysdate(), '%Y%m%d')
    		, LMOTIME = date_format(sysdate(), '%H%i%S')
    		, LMOUSER = #{userData.useract}								
		 where COMPKEY = #{item.compkey}																																		
		   and COOUTKY = #{item.cooutky}
		   and COOUTIT = #{item.cooutit}
		   and UPDTCHK = #{item.updtchk}

    	update WTAKIT			
	       set TCMPQTY = #{item.fordqty}
	     where TASKOKY = #{item.taskoky}
	       and TASKOIT = #{item.taskoit}
	       and TASKSTS = 'TASK'

    	update WSHPIT
    	set 
    		  SHPDCST = (case when SHPDCST = 'NEW' then 'NEW' ELSE 'P_ALOC' end)
    		, SHPITST = (case when SHPDCST = 'NEW' then 'NEW' ELSE 'P_ALOC' end)
    		, SHCUQTY = SHCUQTY + #{item.scitqty}
    		, RGITQTY = RGITQTY + #{item.scitqty}
    		, LMODATE = to_char(now(), 'YYYYMMDD')
    		, LMOTIME = to_char(now(), 'hh24miss')
    		, LMOUSER = #{userData.useract}
    	where COMPKEY = #{item.compkey}
    	and DOCCATE = '700'
    	and	DOCTYPE = (case when #{item.doctype} = '310'
				   			  then '750'
				   			  when #{item.doctype} = '330'
				   			  then '760'
				   			  when #{item.doctype} = '370'
				   			  then '770' end)
		and REFSODC = #{item.cooutky}
		and REFSOIT = #{item.cooutit}

mapper.insert:
