select STK.ROWKEY as rowkey , STK.COMPKEY as compkey , STK.WAREKEY as warekey , WM.WHNAMLC as whnamlc , STK.OWNERKY as ownerky , OW.OWNAMLC as ownamlc , STK.BRANDCD as brandcd , CU.CUNAMLC as cunamlc , STK.SKUMKEY as skumkey , STK.SKUDESC as skudesc , STK.STOTQTY as stotqty , STK.STKSTAT as stkstat , CD.COMCDTX as comcdtx from ( select CONCAT(W1.COMPKEY , W1.STOCKKY) as rowkey , W1.COMPKEY as compkey, W1.WAREKEY as warekey , W1.OWNERKY as ownerky , W1.SKUMKEY as skumkey, W1.SKUDESC as skudesc , W1.LOCAKEY as brandcd , SUM(W1.STOTQTY) as stotqty , W1.STKSTAT as stkstat from WSTKKY W1 where 1=1 and W1.COMPKEY = #{compkey} and (W1.WAREKEY = 'WHOLESALE' and W1.LOCAKEY in
#{item}
and W1.STKSTAT = '80' ) group by WAREKEY,OWNERKY, SKUMKEY, STKSTAT , BRANDCD union all select CONCAT(W2.COMPKEY , W2.STOCKKY) as rowkey , W2.COMPKEY as compkey , W2.WAREKEY as warekey , W2.OWNERKY as ownerky , W2.SKUMKEY as skumkey , W2.SKUDESC as skudesc , M.BRANDCD as brandcd , SUM(W2.STOTQTY) as stotqty , W2.STKSTAT as stkstat from WSTKKY W2 inner join MSKUWC M on W2.COMPKEY = M.COMPKEY and W2.SKUMKEY = M.SKUMKEY and W2.OWNERKY = M.OWNERKY where 1=1 and W2.COMPKEY = M.COMPKEY and W2.WAREKEY = M.WAREKEY and W2.AREAKEY = 'STG' and W2.STOTQTY > 0 and W2.SALLQTY = 0 and W2.SINBQTY = 0 and W2.SOUBQTY = 0 and W2.SBLOQTY = 0 and M.BRANDCD in
#{item}
and W2.WAREKEY in ( select distinct CW.MNGWHKY from MCUSWH CW where W2.COMPKEY = CW.COMPKEY and CW.CUSTKEY in
#{item}
) group by WAREKEY, OWNERKY, SKUMKEY, STKSTAT , BRANDCD order by WAREKEY, OWNERKY, SKUMKEY, STKSTAT ) STK inner join MWARMA WM on STK.COMPKEY = WM.COMPKEY and STK.WAREKEY = WM.WAREKEY inner join MOWRMA OW on STK.COMPKEY = OW.COMPKEY and STK.OWNERKY = OW.OWNERKY inner join MCODEM CD on STK.COMPKEY = CD.COMPKEY and CD.COMCDKY = 'STKSTAT' and STK.STKSTAT = CD.COMCDVL inner join MCUSMA CU on STK.COMPKEY = CU.COMPKEY and STK.BRANDCD = CU.CUSTKEY and CU.CUSTTYP = 'WHOLESALE'
